export const processScenario = (scenario: Scenario): { results: Result[] } => {
  const items = scenario.steps[0].items;
  const premium =
    items.length === 0
      ? PROCESSING_FEE
      : (items[0] as { type: string }).type === "amulet"
        ? 71
        : 115;
  return { results: [{ premium }] };
};
